package com.samlong.controller;
import com.samlong.model.Slide;import com.samlong.repository.SlideRepository;import com.samlong.service.AuditLogService;import org.springframework.data.domain.*;import org.springframework.data.jpa.domain.Specification;import org.springframework.security.authentication.AnonymousAuthenticationToken;import org.springframework.security.core.Authentication;import org.springframework.web.bind.annotation.*;import javax.persistence.criteria.Predicate;import javax.validation.Valid;import java.util.*;
@RestController @RequestMapping("/api/slides") public class SlideController{
 private final SlideRepository repo;private final AuditLogService audit;public SlideController(SlideRepository r,AuditLogService a){repo=r;audit=a;}
 @GetMapping public Object all(Authentication auth,@RequestParam(required=false) Integer page,@RequestParam(defaultValue="10") Integer size,@RequestParam(required=false) String keyword,@RequestParam(required=false) String status){if(isAdmin(auth)&&page!=null){Specification<Slide> spec=(root,query,cb)->{List<Predicate> p=new ArrayList<Predicate>();if(hasText(keyword)){String value="%"+keyword.trim().toLowerCase()+"%";p.add(cb.or(cb.like(cb.lower(root.<String>get("title")),value),cb.like(cb.lower(root.<String>get("subtitle")),value),cb.like(cb.lower(root.<String>get("eyebrow")),value)));}if(hasText(status))p.add(cb.equal(root.get("status"),status));return cb.and(p.toArray(new Predicate[0]));};return repo.findAll(spec,PageRequest.of(Math.max(0,page),safeSize(size),Sort.by("sortOrder").ascending().and(Sort.by("id").ascending())));}return isAdmin(auth)?repo.findAll(Sort.by("sortOrder").ascending().and(Sort.by("id"))):repo.findByStatusOrderBySortOrderAscIdAsc("ACTIVE");}
 private boolean isAdmin(Authentication auth){return auth!=null&&auth.isAuthenticated()&&!(auth instanceof AnonymousAuthenticationToken);}private boolean hasText(String v){return v!=null&&!v.trim().isEmpty();}private int safeSize(Integer size){return Math.min(100,Math.max(1,size==null?10:size));}
 @PostMapping public Slide create(@Valid @RequestBody Slide v){v.setId(null);Slide saved=repo.save(v);audit.record("CREATE","SLIDE",saved.getId(),saved.getTitle());return saved;}@PutMapping("/{id}")public Slide update(@PathVariable Long id,@Valid @RequestBody Slide v){v.setId(id);Slide saved=repo.save(v);audit.record("UPDATE","SLIDE",saved.getId(),saved.getTitle());return saved;}@DeleteMapping("/{id}")public void delete(@PathVariable Long id){Slide v=repo.findById(id).orElseThrow(()->new org.springframework.web.server.ResponseStatusException(org.springframework.http.HttpStatus.NOT_FOUND));repo.delete(v);audit.record("DELETE","SLIDE",id,v.getTitle());}
}
